CREATE TABLE IF NOT EXISTS usuarios (id INTEGER PRIMARY KEY AUTOINCREMENT,nome TEXT NOT NULL,email TEXT NOT NULL COLLATE NOCASE UNIQUE,senha_hash TEXT NOT NULL,perfil TEXT NOT NULL CHECK(perfil IN('ADMIN','COORDENADOR','PROFESSOR')),ativo INTEGER NOT NULL DEFAULT 1 CHECK(ativo IN(0,1)),tentativas_login INTEGER NOT NULL DEFAULT 0,bloqueado_ate TEXT,ultimo_login_em TEXT,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS disciplinas (id INTEGER PRIMARY KEY AUTOINCREMENT,nome TEXT NOT NULL COLLATE NOCASE UNIQUE,ativo INTEGER NOT NULL DEFAULT 1 CHECK(ativo IN(0,1)),criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS professores (id INTEGER PRIMARY KEY AUTOINCREMENT,usuario_id INTEGER NOT NULL UNIQUE,ativo INTEGER NOT NULL DEFAULT 1 CHECK(ativo IN(0,1)),criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(usuario_id) REFERENCES usuarios(id));
CREATE TABLE IF NOT EXISTS vinculos_professor_turma_disciplina (id INTEGER PRIMARY KEY AUTOINCREMENT,professor_id INTEGER NOT NULL,turma_externa_id INTEGER NOT NULL,turma_nome_snapshot TEXT NOT NULL,turma_ano_letivo_snapshot INTEGER NOT NULL,disciplina_id INTEGER NOT NULL,ativo INTEGER NOT NULL DEFAULT 1 CHECK(ativo IN(0,1)),criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(professor_id) REFERENCES professores(id),FOREIGN KEY(disciplina_id) REFERENCES disciplinas(id),UNIQUE(professor_id,turma_externa_id,disciplina_id));
CREATE TABLE IF NOT EXISTS periodos_pre_conselho (id INTEGER PRIMARY KEY AUTOINCREMENT,nome TEXT NOT NULL,ano_letivo INTEGER NOT NULL,etapa TEXT NOT NULL,data_inicio TEXT NOT NULL,data_fim TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'RASCUNHO' CHECK(status IN('RASCUNHO','ABERTO','ENCERRADO')),criado_por INTEGER NOT NULL,encerrado_por INTEGER,encerrado_em TEXT,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(criado_por) REFERENCES usuarios(id),FOREIGN KEY(encerrado_por) REFERENCES usuarios(id));
CREATE TABLE IF NOT EXISTS relatorios_pre_conselho (id INTEGER PRIMARY KEY AUTOINCREMENT,periodo_id INTEGER NOT NULL,vinculo_id INTEGER NOT NULL,status TEXT NOT NULL DEFAULT 'PENDENTE' CHECK(status IN('PENDENTE','RASCUNHO','ENVIADO','DEVOLVIDO','APROVADO')),possui_alunos_rav INTEGER CHECK(possui_alunos_rav IN(0,1)),dificuldades_gerais TEXT,medidas_adotadas TEXT,observacoes_professor TEXT,parecer_coordenacao TEXT,enviado_em TEXT,devolvido_em TEXT,aprovado_em TEXT,aprovado_por INTEGER,liberado_fora_prazo INTEGER NOT NULL DEFAULT 0,versao INTEGER NOT NULL DEFAULT 1,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(periodo_id) REFERENCES periodos_pre_conselho(id),FOREIGN KEY(vinculo_id) REFERENCES vinculos_professor_turma_disciplina(id),FOREIGN KEY(aprovado_por) REFERENCES usuarios(id),UNIQUE(periodo_id,vinculo_id));
CREATE TABLE IF NOT EXISTS relatorio_alunos (id INTEGER PRIMARY KEY AUTOINCREMENT,relatorio_id INTEGER NOT NULL,aluno_externo_id INTEGER NOT NULL,aluno_nome_snapshot TEXT NOT NULL,aluno_data_nascimento_snapshot TEXT NOT NULL,turma_externa_id INTEGER NOT NULL,nota REAL,motivo_rav TEXT NOT NULL,dificuldades TEXT NOT NULL,intervencoes TEXT NOT NULL,observacao TEXT,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,atualizado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(relatorio_id) REFERENCES relatorios_pre_conselho(id) ON DELETE CASCADE,UNIQUE(relatorio_id,aluno_externo_id));
CREATE TABLE IF NOT EXISTS historico_status_relatorio (id INTEGER PRIMARY KEY AUTOINCREMENT,relatorio_id INTEGER NOT NULL,status_anterior TEXT,status_novo TEXT NOT NULL,usuario_id INTEGER NOT NULL,justificativa TEXT,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(relatorio_id) REFERENCES relatorios_pre_conselho(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id));
CREATE TABLE IF NOT EXISTS auditoria (id INTEGER PRIMARY KEY AUTOINCREMENT,usuario_id INTEGER,acao TEXT NOT NULL,entidade TEXT NOT NULL,entidade_id INTEGER,dados_anteriores TEXT,dados_novos TEXT,endereco_ip TEXT,user_agent TEXT,criado_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(usuario_id) REFERENCES usuarios(id));
CREATE TABLE IF NOT EXISTS migrations (id INTEGER PRIMARY KEY AUTOINCREMENT,nome TEXT NOT NULL UNIQUE,executada_em TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_relatorios_status_periodo ON relatorios_pre_conselho(periodo_id,status);
CREATE INDEX IF NOT EXISTS idx_relatorios_vinculo ON relatorios_pre_conselho(vinculo_id);
CREATE INDEX IF NOT EXISTS idx_alunos_externo ON relatorio_alunos(aluno_externo_id);
CREATE INDEX IF NOT EXISTS idx_auditoria_usuario_data ON auditoria(usuario_id,criado_em);
CREATE INDEX IF NOT EXISTS idx_historico_relatorio ON historico_status_relatorio(relatorio_id,criado_em);
